import sys
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.child = defaultdict(TrieNode)
        self.is_word = False

class Solution:
    def insert(self, word):
        root = self.root
        for c in word:
            if c not in root.child:
                root.child[c] = TrieNode()
            root = root.child[c]
        root.is_word = True

        return True

def main():
    solution = Solution()
    solution.root = TrieNode()
    word = input()[:-1]
    print(solution.insert(word))

if __name__ == '__main__':
    main()

