#include <iostream>
#include <string>
#include <vector>

using namespace std;

class TrieNode {
public:
    TrieNode* child[26];
    bool is_word;
};

class Solution {
public:
    TrieNode* root;
    bool insert(string &word)
    {
        for (char c : word) {
            if (c >= 'a' && c <= 'z') {
                if (!root.child[c - 'a']) {
                    root.child[c - 'a'] = new TrieNode();
                }
                root = root.child[c - 'a'];
            } else {
                return false;
            }
        }
        root->is_word = true;
        return true;
    }
};

int main() {
    Solution solution;
    solution.root = new TrieNode();
    string word;
    cin >> word;
    cout << (solution.insert(word) ? 'true' : 'false') << endl;
    return 0;
}
